const apiFetch = async (
  resource: string | URL | globalThis.Request,
  config?: RequestInit,
) => {
  if (typeof resource === "string" && resource.startsWith("/api")) {
    config = config || {};
    const token = window.localStorage.getItem("hims_token");
    const hospitalId = window.localStorage.getItem("currentHospitalId") || "h1";
    
    const customHeaders: Record<string, string> = {
      "x-hospital-id": hospitalId,
      Authorization: token ? `Bearer ${token}` : "",
    };

    if (config.headers instanceof Headers) {
      Object.entries(customHeaders).forEach(([key, value]) => {
        (config!.headers as Headers).set(key, value);
      });
    } else {
      config.headers = {
        ...(config.headers || {}),
        ...customHeaders,
      };
    }
  }

  // Handle offline queueing for mutations
  const method = config?.method || "GET";
  if (
    !navigator.onLine &&
    ["POST", "PUT", "DELETE"].includes(method.toUpperCase())
  ) {
    addToOfflineQueue({
      url: typeof resource === "string" ? resource : resource.toString(),
      method: method.toUpperCase(),
      headers: config?.headers || {},
      body: typeof config?.body === "string" ? config.body : undefined,
    });
    toast.info("You are offline. Action queued.");
    // Return a successful response
    return new Response(JSON.stringify({ success: true, offline: true }), {
      status: 200,
      statusText: "OK",
      headers: { "Content-Type": "application/json" },
    });
  }

  try {
    const res = await fetch(resource, config);
    return res;
  } catch (err: any) {
    if (["POST", "PUT", "DELETE"].includes(method.toUpperCase())) {
      addToOfflineQueue({
        url: typeof resource === "string" ? resource : resource.toString(),
        method: method.toUpperCase(),
        headers: config?.headers || {},
        body: typeof config?.body === "string" ? config.body : undefined,
      });
      toast.info("Network error. Action queued.");
      return new Response(JSON.stringify({ success: true, offline: true }), {
        status: 200,
        statusText: "OK",
        headers: { "Content-Type": "application/json" },
      });
    }
    console.error(`Fetch API Network Failure [${method}] ${resource}:`, err);
    throw err;
  }
};

