  useEffect(() => {
    // 1. Detect if HIMS is running in standalone desktop/mobile launcher mode
    const checkIsStandalone = () => {
      const isStandalone =
        window.matchMedia("(display-mode: standalone)").matches ||
        (navigator as any).standalone ||
        document.referrer.includes("android-app://");
      setIsAppStandalone(isStandalone);
    };

    checkIsStandalone();

    // 2. Capture Chrome/Edge install prompt event
    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e);
      setIsInstallable(true);
      console.log(
        "[PWA] beforeinstallprompt captured, ready for system-native app installer integration",
      );
    };

    window.addEventListener("beforeinstallprompt", handleBeforeInstallPrompt);

    // Fallback: If no prompt event, but we aren't standalone, keep it as installable (to show the setup instructions manual)
    const mediaQuery = window.matchMedia("(display-mode: standalone)");
    const handleMediaChange = (e: MediaQueryListEvent) => {
      setIsAppStandalone(e.matches);
    };
    mediaQuery.addEventListener("change", handleMediaChange);

    // Register simple visual check in console on load
    console.log(
      "[PWA] Active Display Mode is standalone:",
      window.matchMedia("(display-mode: standalone)").matches,
    );

    // Listen for Service Worker updates broadcasted from main.tsx
    const handleAppUpdate = (e: any) => {
      const newWorker = e.detail;
      toast(isRTL ? "تحديث متوفر" : "Update Available", {
        description: isRTL ? "يوجد إصدار جديد من التطبيق." : "A new version of the app is available.",
        action: {
          label: isRTL ? "تحديث الآن" : "Update Now",
          onClick: () => {
            newWorker.postMessage("SKIP_WAITING");
          },
        },
        duration: Infinity,
      });
    };

    window.addEventListener("app-update-available", handleAppUpdate);

    return () => {
      window.removeEventListener(
        "beforeinstallprompt",
        handleBeforeInstallPrompt,
      );
      mediaQuery.removeEventListener("change", handleMediaChange);
      window.removeEventListener("app-update-available", handleAppUpdate);
    };
  }, []);

