  const handleDirectFileImport = (file: File) => {
    if (!file) return;
    setUpFileName(file.name);
    setUpFileSize(`${(file.size / 1024).toFixed(1)} KB`);

    // 1. Read as Base64 Data URL for rendering
    const reader = new FileReader();
    reader.onload = () => {
      let resultString = reader.result as string;
      if (file.name.toLowerCase().endsWith(".dcm")) {
        if (resultString.startsWith("data:;base64,")) {
          resultString = resultString.replace(
            "data:;base64,",
            "data:application/dicom;base64,",
          );
        } else if (
          resultString.startsWith("data:application/octet-stream;base64,")
        ) {
          resultString = resultString.replace(
            "data:application/octet-stream;base64,",
            "data:application/dicom;base64,",
          );
        }
      }
      setUpFileBase64(resultString);
    };
    reader.readAsDataURL(file);

    // 2. If it's a DICOM file, extract metadata via dicom-parser right away to pre-populate clinical fields!
    if (file.name.toLowerCase().endsWith(".dcm")) {
      const arrayReader = new FileReader();
      arrayReader.onload = () => {
        try {
          const bytes = new Uint8Array(arrayReader.result as ArrayBuffer);

          let isRealDicom = false;
          // Preamble check
          if (bytes.length > 132) {
            const preamble = String.fromCharCode(
              bytes[128],
              bytes[129],
              bytes[130],
              bytes[131],
            );
            if (preamble === "DICM") {
              isRealDicom = true;
            }
          }

          // Try to decode or parse anyhow
          if (!isRealDicom && bytes.length > 8) {
            try {
              const dataset = dicomParser.parseDicom(bytes);
              if (dataset && Object.keys(dataset.elements).length > 2) {
                isRealDicom = true;
              }
            } catch (e) {}
          }

          if (isRealDicom) {
            const dataset = dicomParser.parseDicom(bytes);

            // Extract core tags
            const pName = dataset.string("x00100010") || "";
            const pId = dataset.string("x00100020") || "";
            const mld = dataset.string("x00080060") || "";
            const desc =
              dataset.string("x0008103e") || dataset.string("x00081030") || "";
            const institution = dataset.string("x00080080") || "";

            // Map modality nicely
            let matchedModality: "CT" | "MR" | "DX" | "US" = "CT";
            if (mld) {
              const cleanedMld = mld.trim().toUpperCase();
              if (cleanedMld === "CT" || cleanedMld === "CT SCAN")
                matchedModality = "CT";
              else if (cleanedMld === "MR" || cleanedMld === "MRI")
                matchedModality = "MR";
              else if (
                cleanedMld === "DX" ||
                cleanedMld === "CR" ||
                cleanedMld === "XA" ||
                cleanedMld === "PX"
              )
                matchedModality = "DX";
              else if (cleanedMld === "US") matchedModality = "US";
            }

            // Try matching in active patient profiles
            if (pId) {
              const matched = patients.find(
                (p) =>
                  p.id.toLowerCase() === pId.toLowerCase() ||
                  (p.uid && p.uid.toLowerCase() === pId.toLowerCase()),
              );
              if (matched) {
                setUpPatientId(matched.id);
              } else if (pName) {
                const matchedByName = patients.find((p) =>
                  p.name.toLowerCase().includes(pName.toLowerCase()),
                );
                if (matchedByName) {
                  setUpPatientId(matchedByName.id);
                }
              }
            } else if (pName) {
              const matchedByName = patients.find((p) =>
                p.name.toLowerCase().includes(pName.toLowerCase()),
              );
              if (matchedByName) {
                setUpPatientId(matchedByName.id);
              }
            }

            if (matchedModality) {
              setUpModality(matchedModality);
            }
            if (desc) {
              setUpDesc(desc);
            }

            const summaryOfFindings = `Clinically extracted DICOM data:\n• Patient Name: ${pName || "Anonymized"}\n• Patient ID: ${pId || "N/A"}\n• Modality Code: ${mld || "N/A"}\n• Inst: ${institution || "N/A"}\n\nReady for primary diagnostic assessment.`;
            setUpFindings(summaryOfFindings);
          }
        } catch (err) {
          console.error("Error reading DICOM study dataset:", err);
        }
      };
      arrayReader.readAsArrayBuffer(file);
    }
  };

