  const syncOfflineQueue = async () => {
    const queue = getOfflineQueue();
    if (queue.length === 0) return;

    let successCount = 0;
    for (const req of queue) {
      try {
        const res = await fetch(req.url, {
          method: req.method,
          headers: req.headers,
          body: req.body,
        });
        if (res.ok) {
          removeFromOfflineQueue(req.id);
          successCount++;
        }
      } catch (err) {
        console.error("Failed to sync queued request", req, err);
      }
    }

    setPendingSyncCount(getOfflineQueue().length);

    if (successCount > 0) {
      toast.success(`Successfully synced ${successCount} queued actions.`);
      fetchData(true);
    }
  };

