  useEffect(() => {
    const updateConstraints = () => {
      const padding = 16;
      const size = 56;
      const winWidth = window.innerWidth;
      const winHeight = window.innerHeight;
      const startX = isRTL ? winWidth - size - 32 : 32;
      const startY = winHeight - size - 32;

      setDragConstraints({
        left: -startX + padding,
        right: winWidth - startX - size - padding,
        top: -startY + padding,
        bottom: winHeight - startY - size - padding,
      });
    };

    updateConstraints();
    window.addEventListener("resize", updateConstraints);
    window.addEventListener("orientationchange", () => {
      setTimeout(updateConstraints, 300);
    });
    const timer = setTimeout(updateConstraints, 500);

    return () => {
      window.removeEventListener("resize", updateConstraints);
      window.removeEventListener("orientationchange", updateConstraints);
      clearTimeout(timer);
    };
  }, [isRTL]);

