                                            ctx.moveTo(360, 195);
                                            ctx.lineTo(550, 195);
                                            ctx.strokeStyle = "#a8a29e";
                                            ctx.stroke();
                                            ctx.beginPath();
                                            ctx.moveTo(380, 190);
