  const handleAddVisit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const isPatient = currentUser?.role === "Patient";
      const payload = { 
        ...newVisit, 
        visit_date: new Date().toISOString(),
        patient_id: isPatient ? currentUser.id : newVisit.patient_id,
        doctor_id: isPatient ? null : currentUser.id 
      };
      
      const res = await apiFetch("/api/hospital-visits", {
        method: "POST",
        body: JSON.stringify(payload),
      });
      if (res.ok) {
        toast.success(isRTL ? "تم تسجيل الزيارة بنجاح" : "Visit recorded successfully");
        setIsVisitModalOpen(false);
        setNewVisit({ status: 'Observation', reason: '', notes: '' });
        fetchData(true);
      }
    } catch (err) {
      toast.error("Failed to add visit");
    }
  };

